<?php
if (session_status() === PHP_SESSION_NONE) session_start();
if (empty($_SESSION['is_logged_in'])) { header('Location: ../connexion.php'); exit; }
if (($_SESSION['user_type'] ?? '') !== 'admin') { header('Location: dashboard.php'); exit; }
require_once __DIR__ . '/../config/database.php';
function h($value): string { return htmlspecialchars((string)$value, ENT_QUOTES, 'UTF-8'); }
$users = fetchAll('SELECT id,nom,postnom,email,phone,role,created_at FROM users WHERE supprimer=0 ORDER BY created_at DESC,id DESC');
$roleLabels = ['admin'=>'Administrateur','gestionnaire'=>'Gestionnaire','serveur'=>'Serveur','cuisinier'=>'Cuisinier','client'=>'Client'];
$counts = array_fill_keys(array_keys($roleLabels), 0);
foreach ($users as $u) if (isset($counts[$u->role])) $counts[$u->role]++;
$adminName = trim(($_SESSION['user_nom'] ?? 'Admin').' '.($_SESSION['user_prenom'] ?? ''));
$initials = strtoupper(substr($_SESSION['user_nom'] ?? 'A',0,1).substr($_SESSION['user_prenom'] ?? '',0,1));
?>
