{background:#eee;color:#555}.actions{display:flex;gap:6px}.icon-btn{width:32px;height:32px;border:1px solid var(--border);border-radius:8px;background:#fff;cursor:pointer;color:#75675f}.icon-btn:hover{color:var(--primary);border-color:var(--primary)}.icon-btn.delete:hover{color:var(--danger);border-color:var(--danger)}.empty{text-align:center;padding:55px;color:var(--muted)}
.overlay{position:fixed;inset:0;background:#1a120e88;display:none;align-items:center;justify-content:center;padding:20px;z-index:100}.overlay.open{display:flex}.modal{width:min(620px,100%);background:#fff;border-radius:20px;box-shadow:0 24px 70px #0004;overflow:hidden}.modal-head{display:flex;justify-content:space-between;padding:22px 24px;border-bottom:1px solid var(--border)}.modal-head h3{font:700 19px var(--display);margin:0}.close{border:0;background:none;font-size:23px;cursor:pointer}.modal-body{padding:24px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:16px}.field label{display:block;font-size:12px;font-weight:700;margin-bottom:7px}.field input,.field select{width:100%;padding:11px;border:1px solid var(--border);border-radius:10px;font:14px var(--font);outline:none}.full{grid-column:1/-1}.modal-actions{display:flex;justify-content:flex-end;gap:9px;padding:18px 24px;border-top:1px solid var(--border)}.toast{position:fixed;right:22px;bottom:22px;background:#1A120E;color:#fff;padding:14px 18px;border-radius:11px;z-index:200;box-shadow:0 10px 30px #0003}.mobile-overlay{display:none}
@media(max-width:1100px){.stats{grid-template-columns:repeat(3,1fr)}}@media(max-width:768px){.sidebar{transform:translateX(-100%);transition:.2s}.sidebar.open{transform:none}.mobile-overlay.open{display:block;position:fixed;inset:0;background:#0006;z-index:15}.main{margin-left:0}.menu-btn{display:block}.topbar{padding:14px 18px}.content{padding:20px 16px}.stats{grid-template-columns:repeat(2,1fr)}.toolbar{align-items:stretch;flex-direction:column}.tools{flex-wrap:wrap}.grid{grid-template-columns:1fr}.full{grid-column:auto}}@media(max-width:480px){.stats{grid-template-columns:1fr}}
