<aside class="sidebar" id="sidebar"><div class="brand"><div class="brand-icon"><i class="bi bi-cup-hot-fill"></i></div><div><h1>ISSALE</h1><small>Administration</small></div></div>
<nav><div class="nav-label">Menu</div><a class="nav-link" href="dashboard.php"><i class="bi bi-grid-1x2"></i>Tableau de bord</a><a class="nav-link" href="menus.php"><i class="bi bi-journal-richtext"></i>Menus</a><a class="nav-link" href="categories.php"><i class="bi bi-tags"></i>Catégories</a><a class="nav-link" href="tables.php"><i class="bi bi-grid-3x3-gap"></i>Tables</a><a class="nav-link active" href="utilisateurs.php"><i class="bi bi-people"></i>Utilisateurs</a><a class="nav-link" href="settings.php"><i class="bi bi-gear"></i>Paramètres</a></nav>
<div class="sidebar-user"><div class="avatar"><?=h($initials)?></div><div><p><?=h($adminName)?></p><span>Administrateur</span></div><a class="logout" href="../models/logout.php" title="Déconnexion"><i class="bi bi-box-arrow-right"></i></a></div></aside><div class="mobile-overlay" id="mobileOverlay" onclick="toggleSidebar()"></div>
<main class="main"><header class="topbar"><div style="display:flex;align-items:center;gap:12px"><button class="menu-btn" onclick="toggleSidebar()"><i class="bi bi-list"></i></button><div><h2>Utilisateurs</h2><small>Gérez les accès de votre équipe</small></div></div><span class="badge role-admin">Administrateur</span></header>
<section class="content"><div class="crumb"><a href="dashboard.php">Tableau de bord</a> &nbsp;/&nbsp; Utilisateurs</div>
<div class="stats"><?php foreach($roleLabels as $key=>$label): ?><div class="stat"><span><?=h($label)?></span><strong><?=$counts[$key]?></strong></div><?php endforeach; ?></div>
<div class="toolbar"><div class="search"><i class="bi bi-search"></i><input id="search" placeholder="Rechercher un utilisateur…" oninput="filterUsers()"></div><div class="tools"><select class="filter" id="roleFilter" onchange="filterUsers()"><option value="">Tous les rôles</option><?php foreach($roleLabels as $key=>$label): ?><option value="<?=h($key)?>"><?=h($label)?></option><?php endforeach; ?></select><button class="btn btn-primary" onclick="openUser()"><i class="bi bi-plus-lg"></i>Ajouter</button></div></div>
<div class="table-card"><div class="table-wrap"><table><thead><tr><th>Utilisateur</th><th>Email</th><th>Téléphone</th><th>Rôle</th><th>Création</th><th>Actions</th></tr></thead><tbody id="userRows">
<?php if(!$users): ?><tr><td colspan="6" class="empty"><i class="bi bi-people"></i><br>Aucun utilisateur enregistré.</td></tr><?php endif; ?>
<?php foreach($users as $u): $full=trim($u->nom.' '.$u->postnom); ?><tr id="user-<?=$u->id?>" data-role="<?=h($u->role)?>" data-search="<?=h(strtolower($full.' '.$u->email.' '.($u->phone??'')))?>"><td><span class="user-avatar"><?=h(strtoupper(substr($u->nom,0,1).substr($u->postnom,0,1)))?></span><span class="user-name"><?=h($full)?></span></td><td><?=h($u->email)?></td><td><?=h($u->phone ?: '—')?></td><td><span class="badge role-<?=h($u->role)?>"><?=h($roleLabels[$u->role]??$u->role)?></span></td><td><?=date('d/m/Y',strtotime($u->created_at))?></td><td><div class="actions"><button class="icon-btn" title="Modifier" onclick='editUser(<?=json_encode($u,JSON_HEX_APOS|JSON_HEX_QUOT)?>)'><i class="bi bi-pencil"></i></button><?php if((int)$u->id!==(int)$_SESSION['user_id']): ?><button class="icon-btn delete" title="Supprimer" onclick="deleteUser(<?=$u->id?>,<?=h(json_encode($full))?>)"><i class="bi bi-trash"></i></button><?php endif; ?></div></td></tr><?php endforeach; ?>
</tbody></table></div></div></section></main></div>
<div class="overlay" id="userModal"><form class="modal" id="userForm" onsubmit="saveUser(event)"><div class="modal-head"><h3 id="modalTitle">Ajouter un utilisateur</h3><button type="button" class="close" onclick="closeUser()">×</button></div><div class="modal-body"><input type="hidden" name="action" id="action" value="create"><input type="hidden" name="id" id="userId"><div class="grid"><div class="field"><label>Nom *</label><input name="nom" id="nom" required></div><div class="field"><label>Postnom *</label><input name="postnom" id="postnom" required></div><div class="field full"><label>Email *</label><input type="email" name="email" id="email" required></div><div class="field"><label>Téléphone</label><input name="phone" id="phone"></div><div class="field"><label>Rôle *</label><select name="role" id="role" required><?php foreach($roleLabels as $key=>$label): ?><option value="<?=h($key)?>"><?=h($label)?></option><?php endforeach; ?></select></div><div class="field full"><label>Mot de passe <span id="passwordInfo">(4 caractères minimum)</span></label><input type="password" name="password" id="password" minlength="4"></div></div></div><div class="modal-actions"><button type="button" class="btn btn-light" onclick="closeUser()">Annuler</button><button class="btn btn-primary" id="saveBtn">Enregistrer</button></div></form></div>
<script>
const modal=document.getElementById('userModal'),form=document.getElementById('userForm');
function toggleSidebar(){document.getElementById('sidebar').classList.toggle('open');document.getElementById('mobileOverlay').classList.toggle('open')}
function openUser(){form.reset();action.value='create';userId.value='';modalTitle.textContent='Ajouter un utilisateur';password.required=true;passwordInfo.textContent='(4 caractères minimum)';modal.classList.add('open')}
function editUser(u){form.reset();action.value='update';userId.value=u.id;nom.value=u.nom;postnom.value=u.postnom;email.value=u.email;phone.value=u.phone||'';role.value=u.role;password.required=false;passwordInfo.textContent='(laisser vide pour conserver)';modalTitle.textContent='Modifier l’utilisateur';modal.classList.add('open')}
function closeUser(){modal.classList.remove('open')}
async function saveUser(e){e.preventDefault();const btn=document.getElementById('saveBtn');btn.disabled=true;try{const data=Object.fromEntries(new FormData(form));const r=await fetch('../models/traitement/utilisateurs-post.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});const out=await r.json();showToast(out.message);if(out.success)setTimeout(()=>location.reload(),700)}catch(e){showToast('Une erreur est survenue.')}finally{btn.disabled=false}}
async function deleteUser(id,name){if(!confirm('Supprimer '+name+' ?'))return;const r=await fetch('../models/traitement/utilisateurs-post.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'delete',id})});const out=await r.json();showToast(out.message);if(out.success)document.getElementById('user-'+id)?.remove()}
function filterUsers(){const q=document.getElementById('search').value.toLowerCase(),r=document.getElementById('roleFilter').value;document.querySelectorAll('#userRows tr[data-search]').forEach(x=>x.style.display=(!q||x.dataset.search.includes(q))&&(!r||x.dataset.role===r)?'':'none')}
function showToast(message){document.querySelector('.toast')?.remove();const t=document.createElement('div');t.className='toast';t.textContent=message;document.body.append(t);setTimeout(()=>t.remove(),3500)}
modal.addEventListener('click',e=>{if(e.target===modal)closeUser()});
</script><script src="../assets/js/sidebar-sync.js?v=3"></script></body></html>
